using sv_552bcce07fad47c8ba49afabcba4c6e8.Client.Services;

namespace sv_552bcce07fad47c8ba49afabcba4c6e8.Services;

/// <summary>
/// Server-side implementation that simulates a slow backend.
/// </summary>
public class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, ShipmentDetails> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-001"] = new ShipmentDetails(
            TrackingNumber: "TRK-001",
            Status: "In Transit",
            Location: "Chicago, IL",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 25, 17, 0, 0, TimeSpan.Zero),
            StatusUpdates: new List<StatusUpdate>
            {
                new("Order Placed", "New York, NY", new DateTimeOffset(2026, 5, 18, 9, 0, 0, TimeSpan.Zero)),
                new("Picked Up", "New York, NY", new DateTimeOffset(2026, 5, 19, 14, 30, 0, TimeSpan.Zero)),
                new("In Transit", "Chicago, IL", new DateTimeOffset(2026, 5, 21, 8, 15, 0, TimeSpan.Zero)),
            }),
        ["TRK-002"] = new ShipmentDetails(
            TrackingNumber: "TRK-002",
            Status: "Delivered",
            Location: "San Francisco, CA",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 20, 12, 0, 0, TimeSpan.Zero),
            StatusUpdates: new List<StatusUpdate>
            {
                new("Order Placed", "Seattle, WA", new DateTimeOffset(2026, 5, 15, 10, 0, 0, TimeSpan.Zero)),
                new("Picked Up", "Seattle, WA", new DateTimeOffset(2026, 5, 16, 8, 0, 0, TimeSpan.Zero)),
                new("In Transit", "Portland, OR", new DateTimeOffset(2026, 5, 17, 12, 0, 0, TimeSpan.Zero)),
                new("Out for Delivery", "San Francisco, CA", new DateTimeOffset(2026, 5, 20, 7, 30, 0, TimeSpan.Zero)),
                new("Delivered", "San Francisco, CA", new DateTimeOffset(2026, 5, 20, 11, 45, 0, TimeSpan.Zero)),
            }),
        ["TRK-003"] = new ShipmentDetails(
            TrackingNumber: "TRK-003",
            Status: "Out for Delivery",
            Location: "Austin, TX",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 22, 18, 0, 0, TimeSpan.Zero),
            StatusUpdates: new List<StatusUpdate>
            {
                new("Order Placed", "Dallas, TX", new DateTimeOffset(2026, 5, 20, 11, 0, 0, TimeSpan.Zero)),
                new("Picked Up", "Dallas, TX", new DateTimeOffset(2026, 5, 20, 16, 0, 0, TimeSpan.Zero)),
                new("In Transit", "Waco, TX", new DateTimeOffset(2026, 5, 21, 14, 0, 0, TimeSpan.Zero)),
                new("Out for Delivery", "Austin, TX", new DateTimeOffset(2026, 5, 22, 6, 45, 0, TimeSpan.Zero)),
            }),
    };

    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        // Simulate slow backend
        await Task.Delay(1500, ct);

        if (SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

        throw new KeyNotFoundException($"No shipment found for tracking number '{trackingNumber}'.");
    }
}

